import 'package:flutter/material.dart'; import '../core/text_direction_utils.dart';
class EventFieldRow extends StatelessWidget{final String label; final String? value; const EventFieldRow({super.key,required this.label,required this.value}); @override Widget build(BuildContext context){if(value==null||value!.trim().isEmpty)return const SizedBox.shrink(); return Padding(padding:const EdgeInsets.symmetric(vertical:6),child:Row(crossAxisAlignment:CrossAxisAlignment.start,children:[SizedBox(width:120,child:Text(label,style:TextStyle(color:Theme.of(context).colorScheme.outline))),Expanded(child:SmartText(value!,style:const TextStyle(fontWeight:FontWeight.w600)))]));}}
